import { z } from 'zod';

/**
 * Source of an extracted entity.
 * - regex: SDK-side or backend-side regex detector
 * - model: ML inference (GLiNER / DeBERTa head)
 * - hint:  caller-supplied bootstrap entity
 */
export const EntitySourceEnum = z.enum(['regex', 'model', 'hint']);
export type EntitySource = z.infer<typeof EntitySourceEnum>;

/**
 * v3 sensitivity tier returned by ml.privent.ai's NuExtract + validators path.
 */
export const EntitySensitivityEnum = z.enum(['low', 'medium', 'high', 'critical']);
export type EntitySensitivity = z.infer<typeof EntitySensitivityEnum>;

/**
 * Single extracted entity. Span is half-open [start, end) over the original text,
 * zero-indexed UTF-16 code units (matching JS String.prototype.slice).
 *
 * v3 fields (`label`, `category`, `sensitivity`, `risk_reason`, `validated_by`)
 * are populated on the NuExtract path and `null` on the legacy presidio path.
 */
export const EntityItemSchema = z
  .object({
    kind: z.string().min(1).max(64),
    value: z.string(),
    span: z
      .tuple([z.number().int().nonnegative(), z.number().int().nonnegative()])
      .refine(([s, e]) => e > s, {
        message: 'span end must be strictly greater than span start',
      }),
    confidence: z.number().min(0).max(1),
    source: EntitySourceEnum,
    label: z.string().min(1).max(128).nullable().optional(),
    category: z.string().min(1).max(64).nullable().optional(),
    sensitivity: EntitySensitivityEnum.nullable().optional(),
    risk_reason: z.string().min(1).max(512).nullable().optional(),
    validated_by: z.array(z.string().min(1).max(64)).max(16).nullable().optional(),
  })
  .strict();
export type EntityItemV1 = z.infer<typeof EntityItemSchema>;
