import { PriventVaultDestroyedError } from '../errors.js';
import { HttpClient } from '../http.js';
import type {
  TokenVault,
  TokenVaultBatchItem,
  TokenVaultBatchResult,
  VaultFactory,
} from '../interfaces.js';
import type { EntityKind, TokenEntry } from '../types.js';
import { normalize } from './memory.js';

const DEFAULT_TTL_MS = 60 * 60 * 1000;

interface FindOrCreateRequestItem {
  kind: EntityKind;
  normalizedValue: string;
  originalValue: string;
  ttlMs: number;
}

interface FindOrCreateResponse {
  tokens: Array<{ kind: EntityKind; value: string; token: string }>;
}

interface RetrieveResponse {
  entries: Array<{ token: string; kind: EntityKind; value: string }>;
}

interface DestroyResponse {
  deleted: number;
}

/**
 * Postgres-backed vault that shares token state across n8n workers, LangGraph
 * subprocesses, and any other multi-host SDK consumers. Tokens are AES-256-GCM
 * encrypted at rest; deterministic lookup is HMAC-SHA256 over `(kind ||
 * normalized(value))`. SDK normalises locally before sending — the backend
 * never sees the raw value for hashing.
 *
 * The optional {@link TokenVault.findOrCreateBatch} method folds the tokeniser
 * hot path into a single HTTP round-trip, so processing 20 detections on a
 * cloud vault costs the same as one in-memory loop iteration plus one wire
 * call instead of 60 per-entity roundtrips.
 */
export class CloudTokenVault implements TokenVault {
  private destroyed = false;

  constructor(
    readonly sessionId: string,
    private readonly http: HttpClient,
    private readonly defaultTtlMs: number = DEFAULT_TTL_MS,
  ) {}

  async findOrCreateBatch(
    items: TokenVaultBatchItem[],
  ): Promise<TokenVaultBatchResult[]> {
    this.assertAlive();
    const payload: { sessionId: string; items: FindOrCreateRequestItem[] } = {
      sessionId: this.sessionId,
      items: items.map((it) => ({
        kind: it.kind,
        normalizedValue: normalize(it.kind, it.value),
        originalValue: it.value,
        ttlMs: it.ttlMs ?? this.defaultTtlMs,
      })),
    };
    const res = await this.http.request<FindOrCreateResponse>(
      '/v1/vault/find-or-create-batch',
      { method: 'POST', body: payload },
    );
    return res.tokens;
  }

  // ─── N=1 wrappers ─ all delegate to findOrCreateBatch / retrieve so the
  //     server-allocated counter and dedup logic stay in one place. ───────

  async store(entry: TokenEntry): Promise<void> {
    await this.findOrCreateBatch([
      ...(entry.ttlMs != null
        ? [{ kind: entry.kind, value: entry.value, ttlMs: entry.ttlMs }]
        : [{ kind: entry.kind, value: entry.value }]),
    ]);
  }

  async findByValue(value: string, kind: EntityKind): Promise<TokenEntry | null> {
    const [row] = await this.findOrCreateBatch([{ kind, value }]);
    if (!row) return null;
    return {
      token: row.token,
      value: row.value,
      kind: row.kind,
      sessionId: this.sessionId,
      createdAt: Date.now(),
    };
  }

  async retrieve(token: string): Promise<TokenEntry | null> {
    this.assertAlive();
    const res = await this.http.request<RetrieveResponse>(
      '/v1/vault/retrieve-batch',
      {
        method: 'POST',
        body: { sessionId: this.sessionId, tokens: [token] },
      },
    );
    const row = res.entries[0];
    if (!row) return null;
    return {
      token: row.token,
      value: row.value,
      kind: row.kind,
      sessionId: this.sessionId,
      createdAt: Date.now(),
    };
  }

  async listBySession(): Promise<TokenEntry[]> {
    // Cloud vault doesn't expose a list endpoint; tokenizer hot path never
    // calls this. Returning empty preserves the interface contract without
    // pretending to enumerate server state.
    this.assertAlive();
    return [];
  }

  async revoke(token: string): Promise<void> {
    // Single-token revoke isn't on the wire — the server only supports
    // `destroy` (session wipe). The in-memory `revoke` exists for TTL
    // expiry which the cloud vault handles via its own retention cron, so
    // there is nothing to do here.
    this.assertAlive();
    void token;
  }

  async nextCounter(_kind: EntityKind): Promise<number> {
    // Cloud counters are server-allocated atomically inside the
    // find-or-create transaction. Calling this on a cloud vault is a
    // programming error — surface a clear message instead of fabricating
    // a number that doesn't reflect server state.
    throw new Error(
      'CloudTokenVault.nextCounter: counter is server-allocated. Use findOrCreateBatch() instead.',
    );
  }

  async destroy(): Promise<void> {
    if (this.destroyed) return;
    this.destroyed = true;
    try {
      await this.http.request<DestroyResponse>('/v1/vault/destroy', {
        method: 'POST',
        body: { sessionId: this.sessionId },
      });
    } catch {
      // Destroy is best-effort: if the call fails, the retention cron
      // will sweep the entries within an hour. Throwing here would
      // break the existing `finally { await vault.destroy() }` pattern
      // in tokenizer-using code.
    }
  }

  private assertAlive(): void {
    if (this.destroyed) throw new PriventVaultDestroyedError(this.sessionId);
  }
}

export class CloudVaultFactory implements VaultFactory {
  constructor(private readonly http: HttpClient, private readonly defaultTtlMs?: number) {}

  create(sessionId: string): TokenVault {
    return new CloudTokenVault(sessionId, this.http, this.defaultTtlMs);
  }
}
