import type { TokenVault } from '../interfaces.js';

/**
 * Matches `[KIND_NNN]` and the optional HMAC suffix `[KIND_NNN_a4f2]`.
 * Pattern is linear-time with no backtracking.
 */
export const TOKEN_RE = /\[([A-Z][A-Z0-9_]{1,31})_(\d{1,10})(?:_[a-f0-9]{4,16})?\]/g;

/**
 * Collects every `[KIND_NNN]` token string found anywhere in `value`.
 * Pure synchronous scan — used before the async vault resolution pass.
 */
export function* scanForTokens(
  value: unknown,
  seen = new WeakSet<object>(),
  depth = 0,
): Iterable<string> {
  if (depth > 64 || value == null) return;

  if (typeof value === 'string') {
    if (value.indexOf('[') === -1) return;
    for (const match of value.matchAll(new RegExp(TOKEN_RE.source, 'g'))) {
      yield match[0];
    }
    return;
  }

  if (typeof value !== 'object' || ArrayBuffer.isView(value) || value instanceof ArrayBuffer) {
    return;
  }

  if (seen.has(value)) return;
  seen.add(value);

  if (Array.isArray(value)) {
    for (const item of value) {
      yield* scanForTokens(item, seen, depth + 1);
    }
    return;
  }

  for (const v of Object.values(value as Record<string, unknown>)) {
    yield* scanForTokens(v, seen, depth + 1);
  }
}

/**
 * Two-pass async deep detokenize:
 *   1. Collect all token strings (sync).
 *   2. Batch-resolve from vault (async, parallel).
 *   3. Replace tokens in cloned structure (sync).
 *
 * Returns a new value — the original is not mutated.
 * Cycle-safe via WeakSet on the original objects.
 */
export async function detokenizeDeep(
  value: unknown,
  vault: TokenVault,
): Promise<unknown> {
  const allTokens = new Set<string>(scanForTokens(value));
  if (allTokens.size === 0) return value;

  const resolved = new Map<string, string>();
  await Promise.all(
    [...allTokens].map(async (token) => {
      const entry = await vault.retrieve(token);
      if (entry != null) resolved.set(token, entry.value);
    }),
  );

  return replaceIn(value, resolved, new WeakSet(), 0);
}

function replaceIn(
  value: unknown,
  resolved: Map<string, string>,
  seen: WeakSet<object>,
  depth: number,
): unknown {
  if (depth > 64 || value == null) return value;

  if (typeof value === 'string') {
    if (value.indexOf('[') === -1) return value;
    return value.replace(
      new RegExp(TOKEN_RE.source, 'g'),
      (match) => resolved.get(match) ?? match,
    );
  }

  if (typeof value !== 'object' || ArrayBuffer.isView(value) || value instanceof ArrayBuffer) {
    return value;
  }

  if (seen.has(value)) return value;
  seen.add(value);

  if (Array.isArray(value)) {
    return value.map((item) => replaceIn(item, resolved, seen, depth + 1));
  }

  const out: Record<string, unknown> = {};
  for (const [k, v] of Object.entries(value as Record<string, unknown>)) {
    out[k] = replaceIn(v, resolved, seen, depth + 1);
  }
  return out;
}
