import {
  PriventAPIError,
  PriventAuthError,
  PriventVaultCorruptedError,
  PriventCircuitOpenError,
  PriventError,
  PriventNetworkError,
  PriventRateLimitError,
  PriventTimeoutError,
} from './errors.js';
import {
  CircuitBreakerRegistry,
  type CircuitBreakerOptions,
} from './cloud/circuit-breaker.js';
import { parseRetryAfter } from './http/retry-after.js';
import {
  getServiceInstanceId,
  getTracer,
  SPAN_STATUS,
  TRACER_NAME,
  TRACER_VERSION,
} from './otel.js';

export interface HttpClientConfig {
  baseUrl: string;
  apiKey: string;
  maxRetries?: number;
  timeoutMs?: number;
  /**
   * Optional shared CB registry. Pass to coordinate state across HttpClient
   * instances pointing at the same host (e.g., risk-scorer + audit-logger).
   * If omitted, the client owns a private registry.
   */
  circuitBreakers?: CircuitBreakerRegistry;
  /** Tuning for the private registry; ignored when `circuitBreakers` is set. */
  circuitBreakerOptions?: CircuitBreakerOptions;
}

export interface HttpRequestOptions {
  method?: 'GET' | 'POST' | 'PUT' | 'DELETE' | 'PATCH';
  body?: unknown;
  headers?: Record<string, string>;
  signal?: AbortSignal;
  /** Auto-generated UUID if not provided. Reused across retries for idempotency. */
  idempotencyKey?: string;
  /**
   * Optional inbound `X-Request-Id`. When provided, propagated downstream so
   * trace correlation survives across SDK → Backend → ML. When absent, a
   * fresh UUID is generated for the call and reused across retries.
   */
  requestId?: string;
}

export class HttpClient {
  private readonly baseUrl: string;
  private readonly host: string;
  private readonly apiKey: string;
  private readonly maxRetries: number;
  private readonly timeoutMs: number;
  private readonly cbRegistry: CircuitBreakerRegistry;

  constructor(config: HttpClientConfig) {
    this.baseUrl = config.baseUrl.replace(/\/$/, '');
    this.host = new URL(this.baseUrl).host;
    this.apiKey = config.apiKey;
    this.maxRetries = config.maxRetries ?? 2;
    this.timeoutMs = config.timeoutMs ?? 30_000;
    this.cbRegistry =
      config.circuitBreakers ??
      new CircuitBreakerRegistry(config.circuitBreakerOptions);
  }

  /** Test/observability accessor. */
  getCircuitBreakerRegistry(): CircuitBreakerRegistry {
    return this.cbRegistry;
  }

  async request<T>(path: string, opts: HttpRequestOptions = {}): Promise<T> {
    const idempotencyKey = opts.idempotencyKey ?? crypto.randomUUID();
    // Inbound X-Request-Id (any case) wins; otherwise mint one. Reused across
    // retries so traces stay correlated through the entire call.
    const requestId =
      opts.requestId ??
      opts.headers?.['X-Request-Id'] ??
      opts.headers?.['x-request-id'] ??
      crypto.randomUUID();
    const cb = this.cbRegistry.for(this.host);
    const tracer = getTracer();
    const span = tracer.startSpan(`http.client ${opts.method ?? 'GET'} ${path}`, {
      attributes: {
        'http.method': opts.method ?? 'GET',
        'http.url': `${this.baseUrl}${path}`,
        'peer.service': this.host,
        'request.id': requestId,
        'service.name': TRACER_NAME,
        'service.version': TRACER_VERSION,
        'service.instance.id': getServiceInstanceId(),
      },
    });
    let attempt = 0;

    try {
      // eslint-disable-next-line no-constant-condition
      while (true) {
        if (!cb.canRequest()) {
          const e = new PriventCircuitOpenError(this.host, { requestId });
          span.setStatus({ code: SPAN_STATUS.ERROR, message: 'circuit_open' });
          throw e;
        }

        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), this.timeoutMs);
        const signal =
          opts.signal != null
            ? AbortSignal.any([opts.signal, controller.signal])
            : controller.signal;

        try {
          const bodyStr = opts.body != null ? JSON.stringify(opts.body) : null;
          const response = await fetch(`${this.baseUrl}${path}`, {
            method: opts.method ?? 'GET',
            headers: {
              'Content-Type': 'application/json',
              Authorization: `Bearer ${this.apiKey}`,
              'Idempotency-Key': idempotencyKey,
              'X-Request-Id': requestId,
              ...opts.headers,
            },
            ...(bodyStr !== null && { body: bodyStr }),
            signal,
          });

          clearTimeout(timeoutId);

          if (!response.ok) {
            const err = await parseErrorResponse(response, idempotencyKey);
            // Auth/config-class errors do not feed the breaker — they reflect a
            // client mistake, not host health. Mirrors backend's CB invariant.
            if (!(err instanceof PriventAuthError)) cb.recordFailure();

            if (err.retryable && attempt < this.maxRetries) {
              const retryAfter =
                response.status === 429 || response.status === 503
                  ? parseRetryAfter(response.headers)
                  : null;
              await sleep(Math.max(backoff(attempt), retryAfter ?? 0));
              attempt++;
              continue;
            }
            span.setAttribute('http.status_code', response.status);
            span.setStatus({ code: SPAN_STATUS.ERROR, message: err.message });
            throw err;
          }

          cb.recordSuccess();
          span.setAttribute('http.status_code', response.status);
          span.setStatus({ code: SPAN_STATUS.OK });
          return response.json() as Promise<T>;
        } catch (err) {
          clearTimeout(timeoutId);

          if (err instanceof PriventError) {
            if (
              !(err instanceof PriventAuthError) &&
              !(err instanceof PriventCircuitOpenError)
            ) {
              cb.recordFailure();
            }
            span.setStatus({ code: SPAN_STATUS.ERROR, message: err.message });
            throw err;
          }

          if (isAbortError(err)) {
            cb.recordFailure();
            const te = new PriventTimeoutError(
              `Request to ${path} timed out after ${this.timeoutMs}ms`,
              { requestId: idempotencyKey },
            );
            if (attempt < this.maxRetries) {
              await sleep(backoff(attempt));
              attempt++;
              continue;
            }
            span.setStatus({ code: SPAN_STATUS.ERROR, message: 'timeout' });
            throw te;
          }

          cb.recordFailure();
          const ne = new PriventNetworkError(
            `Network error on ${path}: ${String(err)}`,
            {
              requestId: idempotencyKey,
              cause: err,
            },
          );
          if (attempt < this.maxRetries) {
            await sleep(backoff(attempt));
            attempt++;
            continue;
          }
          span.setStatus({ code: SPAN_STATUS.ERROR, message: 'network' });
          span.recordException(err);
          throw ne;
        }
      }
    } finally {
      span.end();
    }
  }
}

async function parseErrorResponse(
  response: Response,
  requestId: string,
): Promise<PriventError> {
  let body: unknown = null;
  try {
    body = await response.json();
  } catch {
    // response body is not JSON
  }

  const remoteRequestId = response.headers.get('x-request-id') ?? requestId;
  const message =
    (body as Record<string, unknown> | null)?.message?.toString() ?? response.statusText;

  if (response.status === 401 || response.status === 403) {
    return new PriventAuthError(message, {
      statusCode: response.status,
      requestId: remoteRequestId,
    });
  }
  if (
    response.status === 422 &&
    (body as Record<string, unknown> | null)?.code === 'VAULT_DECRYPTION_FAILED'
  ) {
    const token = (body as Record<string, unknown>).token;
    return new PriventVaultCorruptedError({
      statusCode: response.status,
      requestId: remoteRequestId,
      ...(typeof token === 'string' && { token }),
    });
  }
  if (response.status === 429) {
    return new PriventRateLimitError(message, {
      statusCode: response.status,
      requestId: remoteRequestId,
    });
  }
  return new PriventAPIError(message, {
    statusCode: response.status,
    requestId: remoteRequestId,
    retryable: response.status >= 500,
  });
}

function isAbortError(err: unknown): boolean {
  return err instanceof DOMException && err.name === 'AbortError';
}

/** Exponential backoff with ±20% jitter. Base 500ms, cap 10s. */
function backoff(attempt: number): number {
  const base = 500;
  const cap = 10_000;
  const exp = Math.min(base * Math.pow(2, attempt), cap);
  // Multiplicative jitter: ±20% of `exp`. Keeps jitter proportional under
  // backoff growth (vs. additive `exp + jitter` which flattens at the cap).
  const jitterFactor = 1 + (Math.random() * 0.4 - 0.2);
  return Math.max(0, exp * jitterFactor);
}

function sleep(ms: number): Promise<void> {
  return new Promise((res) => setTimeout(res, ms));
}
