import type { RiskScorer, AuditLogger, AuditEvent } from '../interfaces.js';
import type { RiskScore } from '../types.js';
import { PriventCredentialsError } from '../errors.js';

/**
 * Default RiskScorer used when no apiKey is configured.
 *
 * Why this exists: previously the keyless path returned a NoopRiskScorer
 * that silently emitted zero-risk scores.  That hides a real configuration
 * bug — users wired Privent into their pipeline expecting actual scoring,
 * never noticed the missing key, and shipped to prod with the cloud
 * layer dark.  This sentinel surfaces the same guided early-access message
 * that n8n and other integrations show, so the misconfiguration fails loud.
 *
 * Note: tokenization continues to work without an apiKey (regex-only mode).
 * Only the cloud-dependent risk endpoint trips this error.
 */
export class MissingCredentialsRiskScorer implements RiskScorer {
  async score(_input: { text: string; context?: string }): Promise<RiskScore> {
    throw new PriventCredentialsError();
  }

  async scoreBatch(_inputs: Array<{ text: string }>): Promise<RiskScore[]> {
    throw new PriventCredentialsError();
  }
}

/**
 * Default AuditLogger used when no apiKey is configured.  Same rationale as
 * {@link MissingCredentialsRiskScorer}: dropping audit events silently is
 * worse than a loud error pointing the operator at the credential setup.
 */
export class MissingCredentialsAuditLogger implements AuditLogger {
  async log(_event: AuditEvent): Promise<void> {
    throw new PriventCredentialsError();
  }
}
