/**
 * OpenTelemetry integration for `@priventai/core`.
 *
 * `@opentelemetry/api` is an *optional* peer dependency: hosts that emit
 * traces install it; everyone else gets a no-op. We import it lazily and
 * dynamically — a missing module never throws on the SDK consumer.
 *
 * Why not just `import { trace } from '@opentelemetry/api'`?
 * Because the public surface forces a hard dep on consumers who don't want
 * tracing. The lazy `getTracer()` returns either a real Tracer or a
 * functionally-equivalent no-op.
 */

export const TRACER_NAME = '@priventai/core';
export const TRACER_VERSION = (() => {
  // Bundlers replace `__SDK_VERSION__`; fallback for unbundled paths.
  // Keep this resilient — the version is only used as an attribute.
  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  const v = (globalThis as any).__SDK_VERSION__;
  return typeof v === 'string' && v.length > 0 ? v : '0.1.0';
})();

/**
 * Stable per-process identity. Repeated `getServiceInstanceId()` calls return
 * the same UUID, exposed as `service.instance.id` on spans and audit events.
 */
let _instanceId: string | null = null;
export function getServiceInstanceId(): string {
  if (_instanceId == null) _instanceId = crypto.randomUUID();
  return _instanceId;
}

/**
 * Test-only seam: allows resetting the cached instance id between runs.
 * Not exported from the package barrel.
 */
export function __resetServiceInstanceIdForTests(): void {
  _instanceId = null;
}

// Minimal subset we actually call. Lets us return a no-op without dragging the
// whole `@opentelemetry/api` shape into our types.
export interface MinimalSpan {
  setAttribute(key: string, value: string | number | boolean): void;
  setStatus(status: { code: number; message?: string }): void;
  recordException(err: unknown): void;
  end(): void;
}

export interface MinimalTracer {
  startSpan(name: string, opts?: { attributes?: Record<string, string | number | boolean> }): MinimalSpan;
}

const NOOP_SPAN: MinimalSpan = {
  setAttribute() {},
  setStatus() {},
  recordException() {},
  end() {},
};

const NOOP_TRACER: MinimalTracer = {
  startSpan: () => NOOP_SPAN,
};

let _cachedTracer: MinimalTracer | null = null;

/**
 * Returns a real OpenTelemetry tracer when `@opentelemetry/api` is loadable,
 * else a no-op. Cached after the first call.
 */
export function getTracer(): MinimalTracer {
  if (_cachedTracer != null) return _cachedTracer;
  try {
    // Synchronous-style require so we don't introduce async hot paths.
    // The bundler (tsup) preserves this as a runtime resolution because
    // `@opentelemetry/api` is declared as a peer dep, not a dependency.
    // eslint-disable-next-line @typescript-eslint/no-require-imports
    const otel = require('@opentelemetry/api') as {
      trace?: { getTracer?: (name: string, version?: string) => MinimalTracer };
    };
    const t = otel?.trace?.getTracer?.(TRACER_NAME, TRACER_VERSION);
    _cachedTracer = t ?? NOOP_TRACER;
  } catch {
    _cachedTracer = NOOP_TRACER;
  }
  return _cachedTracer;
}

/** SpanStatusCode mirror — keeps callers from importing the OTel API directly. */
export const SPAN_STATUS = {
  UNSET: 0,
  OK: 1,
  ERROR: 2,
} as const;
