import { z } from 'zod';
import { EntityItemSchema } from './entities.js';

export const RiskLevelEnum = z.enum(['LOW', 'MEDIUM', 'HIGH', 'CRITICAL']);
export type RiskLevelV1 = z.infer<typeof RiskLevelEnum>;

const UuidV4 = z.string().uuid();
const LangTag = z
  .string()
  .regex(/^(auto|[a-z]{2}(-[A-Z]{2})?)$/, {
    message: 'lang must be "auto" or ISO-639-1 (optional ISO-3166-1 region)',
  });

/**
 * POST /v1/risk/score request.
 *
 * Bounds (DoS guard):
 * - text: 1..10000 chars
 * - bootstrap_entities: max 256
 *
 * Note: the legacy `entity_hints` field was dropped after ml.privent.ai
 * migrated off GLiNER; the server ignores it.
 */
export const ScoreRequestSchema = z
  .object({
    text: z.string().min(1).max(10000),
    lang: LangTag.optional(),
    include_entities: z.boolean().default(false),
    bootstrap_entities: z.array(EntityItemSchema).max(256).optional(),
    session_id: UuidV4.optional(),
    trace_id: UuidV4.optional(),
  })
  .strict();
export type ScoreRequestV1 = z.infer<typeof ScoreRequestSchema>;

/**
 * `model` field contract: `<name>@<semver>+<sha7>`.
 * Examples: "mdeberta-v3-base@0.3.1+a1b2c3d", "regex-only@0.1.0+local".
 */
const ModelIdentifier = z
  .string()
  .regex(/^[a-zA-Z][a-zA-Z0-9._-]*@\d+\.\d+\.\d+(?:-[A-Za-z0-9.-]+)?\+[A-Za-z0-9._-]+$/, {
    message: 'model must be "<name>@<semver>+<build>"',
  });

/**
 * v3 extraction telemetry. Optional — present only on the NuExtract path of
 * ml.privent.ai (`/classify`). Cloud `/v1/risk/score` may omit this.
 */
export const ExtractionMetaSchema = z
  .object({
    engine: z.string().min(1).max(128),
    latency_ms: z.number().nonnegative(),
    build_signature: z.string().min(1).max(64),
  })
  .strict();
export type ExtractionMetaV1 = z.infer<typeof ExtractionMetaSchema>;

/**
 * POST /v1/risk/score response.
 * `entities` is null when include_entities=false; an array (possibly empty) when true.
 *
 * v3 surface adds optional `document_lang` (ISO-639-1) and `extraction_meta`.
 */
export const ScoreResponseSchema = z
  .object({
    risk_score: z.number().min(0).max(1),
    risk_level: RiskLevelEnum,
    categories: z.array(z.string().min(1).max(64)),
    entities: z.array(EntityItemSchema).nullable(),
    model: ModelIdentifier,
    latency_ms: z.number().int().nonnegative(),
    document_lang: z.string().min(1).max(32).nullable().optional(),
    extraction_meta: ExtractionMetaSchema.nullable().optional(),
  })
  .strict();
export type ScoreResponseV1 = z.infer<typeof ScoreResponseSchema>;

/**
 * POST /v1/risk/batch — bounded at 64 items.
 */
export const BatchRequestSchema = z
  .object({
    items: z.array(ScoreRequestSchema).min(1).max(64),
  })
  .strict();
export type BatchRequestV1 = z.infer<typeof BatchRequestSchema>;

/**
 * Backend MUST return results.length === request.items.length, in input order.
 * SDK validates this invariant in CloudRiskScorer.scoreBatch (CP-3).
 */
export const BatchResponseSchema = z
  .object({
    results: z.array(ScoreResponseSchema),
  })
  .strict();
export type BatchResponseV1 = z.infer<typeof BatchResponseSchema>;
